const OAuthConfig = {
  clientId: 'YOUR_CLIENT_ID',
  redirectUri: window.location.origin + '/callback',
  authorizationEndpoint: 'https://oauth-provider.com/oauth/authorize',
  tokenEndpoint: 'https://oauth-provider.com/oauth/token',
  scope: 'read write',
  apiBaseUrl: 'https://api.example.com'
};

function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let result = '';
  const randomValues = new Uint8Array(length);
  crypto.getRandomValues(randomValues);
  for (let i = 0; i < length; i++) {
    result += charset[randomValues[i] % charset.length];
  }
  return result;
}

async function sha256(plain) {
  const encoder = new TextEncoder();
  const data = encoder.encode(plain);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return hash;
}

function base64UrlEncode(arrayBuffer) {
  const bytes = new Uint8Array(arrayBuffer);
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
}

async function generateCodeChallenge(codeVerifier) {
  const hashed = await sha256(codeVerifier);
  return base64UrlEncode(hashed);
}

class OAuthManager {
  constructor(config) {
    this.config = config;
    this.accessToken = localStorage.getItem('access_token');
    this.refreshToken = localStorage.getItem('refresh_token');
    this.tokenExpiry = localStorage.getItem('token_expiry');
  }

  async initiateLogin() {
    const codeVerifier = generateRandomString(128);
    const codeChallenge = await generateCodeChallenge(codeVerifier);
    const state = generateRandomString(32);

    sessionStorage.setItem('code_verifier', codeVerifier);
    sessionStorage.setItem('oauth_state', state);

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: this.config.clientId,
      redirect_uri: this.config.redirectUri,
      scope: this.config.scope,
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256'
    });

    window.location.href = `${this.config.authorizationEndpoint}?${params.toString()}`;
  }

  async handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    const error = urlParams.get('error');

    if (error) {
      throw new Error(`OAuth error: ${error}`);
    }

    const storedState = sessionStorage.getItem('oauth_state');
    if (state !== storedState) {
      throw new Error('State mismatch - possible CSRF attack');
    }

    if (!code) {
      throw new Error('No authorization code received');
    }

    const codeVerifier = sessionStorage.getItem('code_verifier');
    if (!codeVerifier) {
      throw new Error('Code verifier not found');
    }

    await this.exchangeCodeForToken(code, codeVerifier);

    sessionStorage.removeItem('code_verifier');
    sessionStorage.removeItem('oauth_state');

    window.history.replaceState({}, document.title, window.location.pathname);
  }

  async exchangeCodeForToken(code, codeVerifier) {
    const params = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: this.config.redirectUri,
      client_id: this.config.clientId,
      code_verifier: codeVerifier
    });

    const response = await fetch(this.config.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(`Token exchange failed: ${errorData.error || response.statusText}`);
    }

    const data = await response.json();
    this.storeTokens(data);
  }

  storeTokens(tokenData) {
    this.accessToken = tokenData.access_token;
    this.refreshToken = tokenData.refresh_token;
    
    const expiresIn = tokenData.expires_in || 3600;
    this.tokenExpiry = Date.now() + (expiresIn * 1000);

    localStorage.setItem('access_token', this.accessToken);
    if (this.refreshToken) {
      localStorage.setItem('refresh_token', this.refreshToken);
    }
    localStorage.setItem('token_expiry', this.tokenExpiry.toString());
  }

  async refreshAccessToken() {
    if (!this.refreshToken) {
      throw new Error('No refresh token available');
    }

    const params = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: this.refreshToken,
      client_id: this.config.clientId
    });

    const response = await fetch(this.config.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      this.logout();
      throw new Error('Token refresh failed');
    }

    const data = await response.json();
    this.storeTokens(data);
  }

  isTokenExpired() {
    if (!this.tokenExpiry) return true;
    return Date.now() >= parseInt(this.tokenExpiry) - 60000;
  }

  async getValidAccessToken() {
    if (!this.accessToken) {
      throw new Error('Not authenticated');
    }

    if (this.isTokenExpired()) {
      await this.refreshAccessToken();
    }

    return this.accessToken;
  }

  isAuthenticated() {
    return !!this.accessToken && !this.isTokenExpired();
  }

  logout() {
    this.accessToken = null;
    this.refreshToken = null;
    this.tokenExpiry = null;
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    localStorage.removeItem('token_expiry');
    sessionStorage.removeItem('code_verifier');
    sessionStorage.removeItem('oauth_state');
  }

  async apiRequest(endpoint, options = {}) {
    const token = await this.getValidAccessToken();

    const headers = {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
      ...options.headers
    };

    const response = await fetch(`${this.config.apiBaseUrl}${endpoint}`, {
      ...options,
      headers
    });

    if (response.status === 401) {
      try {
        await this.refreshAccessToken();
        const newToken = await this.getValidAccessToken();
        headers['Authorization'] = `Bearer ${newToken}`;
        
        return await fetch(`${this.config.apiBaseUrl}${endpoint}`, {
          ...options,
          headers
        });
      } catch (error) {
        this.logout();
        throw new Error('Authentication failed');
      }
    }

    return response;
  }
}

const oauthManager = new OAuthManager(OAuthConfig);

function App() {
  const [isAuthenticated, setIsAuthenticated] = React.useState(false);
  const [user, setUser] = React.useState(null);
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    const initAuth = async () => {
      const urlParams = new URLSearchParams(window.location.search);
      if (urlParams.has('code')) {
        try {
          await oauthManager.handleCallback();
          setIsAuthenticated(true);
          await fetchUserData();
        } catch (error) {
          console.error('Authentication error:', error);
          alert('Authentication failed: ' + error.message);
        }
      } else if (oauthManager.isAuthenticated()) {
        setIsAuthenticated(true);
        await fetchUserData();
      }
      setLoading(false);
    };

    initAuth();
  }, []);

  const fetchUserData = async () => {
    try {
      const response = await oauthManager.apiRequest('/user');
      const userData = await response.json();
      setUser(userData);
    } catch (error) {
      console.error('Failed to fetch user data:', error);
    }
  };

  const handleLogin = () => {
    oauthManager.initiateLogin();
  };

  const handleLogout = () => {
    oauthManager.logout();
    setIsAuthenticated(false);
    setUser(null);
  };

  const handleApiCall = async () => {
    try {
      const response = await oauthManager.apiRequest('/data');
      const data = await response.json();
      console.log('API Response:', data);
      alert('API call successful! Check console for data.');
    } catch (error) {
      console.error('API call failed:', error);
      alert('API call failed: ' + error.message);
    }
  };

  if (loading) {
    return React.createElement('div', { className: 'container' },
      React.createElement('h1', null, 'Loading...')
    );
  }

  if (!isAuthenticated) {
    return React.createElement('div', { className: 'container' },
      React.createElement('h1', null, 'OAuth 2.0 Authentication'),
      React.createElement('p', null, 'Please login to continue'),
      React.createElement('button', { onClick: handleLogin, className: 'btn-primary' }, 'Login with OAuth')
    );
  }

  return React.createElement('div', { className: 'container' },
    React.createElement('h1', null, 'Welcome!'),
    user && React.createElement('div', { className: 'user-info' },
      React.createElement('h2', null, 'User Information'),
      React.createElement('pre', null, JSON.stringify(user, null, 2))
    ),
    React.createElement('div', { className: 'actions' },
      React.createElement('button', { onClick: handleApiCall, className: 'btn-secondary' }, 'Make API Call'),
      React.createElement('button', { onClick: handleLogout, className: 'btn-danger' }, 'Logout')
    )
  );
}

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(React.createElement(App));

